<?php require_once __DIR__.'/../config/db.php'; require_once __DIR__.'/../config/layout.php'; page_start('Dividendos','dividendos'); $assets=$pdo->query("SELECT id,ticker FROM assets ORDER BY ticker")->fetchAll(PDO::FETCH_ASSOC); $rows=$pdo->query("SELECT d.*,a.ticker FROM dividends d JOIN assets a ON a.id=d.asset_id ORDER BY d.pay_date DESC")->fetchAll(PDO::FETCH_ASSOC); $total=$pdo->query("SELECT COALESCE(SUM(amount),0) FROM dividends")->fetchColumn(); function m($n){return '$'.number_format((float)$n,2);} ?>
<section class="hero"><div><h1>Dividendos</h1><p>Control de ingresos pasivos y cash recibido.</p></div><div class="pill">Total: <?=m($total)?></div></section>
<section class="panel"><h2>Agregar dividendo</h2><form action="../api/add_dividend.php" method="POST" class="form-row"><select name="asset_id"><?php foreach($assets as $a):?><option value="<?=$a['id']?>"><?=$a['ticker']?></option><?php endforeach;?></select><input type="date" name="pay_date" required><input type="number" step="0.01" name="amount" placeholder="Monto" required><input name="note" placeholder="Nota"><button>Agregar</button></form></section>
<section class="panel"><table><thead><tr><th>Fecha</th><th>Activo</th><th>Monto</th><th>Nota</th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><?=$r['pay_date']?></td><td><?=$r['ticker']?></td><td class="green"><?=m($r['amount'])?></td><td><?=htmlspecialchars($r['note'])?></td></tr><?php endforeach;?></tbody></table></section>
<?php page_end(); ?>
